mapper.select:
select c.customer_id, c.customer_name, c.phone, c.sex, c.source, c.level, c.industry, c.tags, c.follow_status, c.next_contact_time, c.belong_user_id, c.belong_dept_id, c.is_pool, c.enter_pool_time, c.last_follow_time, c.address, c.email, c.company, c.position, c.wechat, c.qq, c.del_flag, c.create_by, c.create_time, c.update_by, c.update_time, c.remark, u.user_name as belong_user_name, d.dept_name as belong_dept_name, (select d2.dept_name from crm_customer_share cs left join sys_user u2 on cs.from_user_id = u2.user_id left join sys_dept d2 on u2.dept_id = d2.dept_id where cs.customer_id = c.customer_id and cs.del_flag = '0' and cs.to_user_id = #{params.currentUserId} and (cs.expire_time is null or cs.expire_time > now()) limit 1) as share_from_dept_name, (select case when cs2.to_user_id is not null then concat('已分配至 ', u3.nick_name) when cs2.to_dept_id is not null then concat('已共享至 ', d3.dept_name) else '' end from crm_customer_share cs2 left join sys_user u3 on cs2.to_user_id = u3.user_id left join sys_dept d3 on cs2.to_dept_id = d3.dept_id where cs2.customer_id = c.customer_id and cs2.del_flag = '0' and cs2.from_user_id = #{params.currentUserId} and (cs2.expire_time is null or cs2.expire_time > now()) order by cs2.create_time desc limit 1) as share_action_desc, (select cs3.create_time from crm_customer_share cs3 where cs3.customer_id = c.customer_id and cs3.del_flag = '0' and cs3.from_user_id = #{params.currentUserId} and (cs3.expire_time is null or cs3.expire_time > now()) order by cs3.create_time desc limit 1) as share_action_time, (select group_concat(distinct o2.order_no order by o2.create_time desc separator ', ') from crm_order o2 where o2.customer_id = c.customer_id and o2.del_flag = '0') as order_nos, (select group_concat(distinct ct.contract_no order by ct.create_time desc separator ', ') from crm_contract ct where ct.customer_id = c.customer_id and ct.del_flag = '0') as contract_nos from crm_customer c left join sys_user u on c.belong_user_id = u.user_id left join sys_dept d on c.belong_dept_id = d.dept_id where c.del_flag = '0'
AND c.customer_id = #{customerId}
AND c.customer_name like concat('%', #{customerName}, '%')
AND c.phone like concat('%', #{phone}, '%')
AND c.sex = #{sex}
AND c.source = #{source}
AND c.level = #{level}
AND c.industry like concat('%', #{industry}, '%')
AND c.follow_status = #{followStatus}
AND FIND_IN_SET(#{tag}, c.tags)
AND c.is_pool = #{isPool}
AND c.is_pool = '0'
${params.dataScope}
AND c.belong_user_id = #{belongUserId}
AND c.belong_dept_id = #{belongDeptId}
AND date_format(c.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
AND date_format(c.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
order by FIELD(c.level, 'high', 'medium', 'low', 'won'), c.create_time desc

mapper.update:
update crm_customer
customer_name = #{customerName}, phone = #{phone}, sex = #{sex}, source = #{source}, level = #{level}, industry = #{industry}, tags = #{tags}, follow_status = #{followStatus}, next_contact_time = #{nextContactTime}, belong_user_id = #{belongUserId}, belong_dept_id = #{belongDeptId}, is_pool = #{isPool}, enter_pool_time = #{enterPoolTime}, last_follow_time = #{lastFollowTime}, address = #{address}, email = #{email}, company = #{company}, position = #{position}, wechat = #{wechat}, qq = #{qq}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where customer_id = #{customerId}

update crm_customer
belong_user_id = #{belongUserId}, belong_dept_id = #{belongDeptId}, is_pool = '0', update_by = #{updateBy}, update_time = sysdate()
where customer_id = #{customerId}

mapper.select:
select count(1) from crm_customer c
where c.del_flag = '0'
and (date_format(c.create_time, '%Y-%m-%d') = #{params.today}
     or date_format(c.update_time, '%Y-%m-%d') = #{params.today})

    ${params.dataScope}

select count(1) from crm_customer c
where c.del_flag = '0' and c.follow_status = 'pending'

    ${params.dataScope}

select c.source as name, count(1) as value from crm_customer c where c.del_flag = '0' and c.source is not null and c.source != ''
${params.dataScope}
group by c.source

select c.level as name, count(1) as value from crm_customer c where c.del_flag = '0' and c.level is not null and c.level != ''
${params.dataScope}
group by c.level

SELECT DATE_FORMAT(c.create_time, '%Y-%m') AS month, COUNT(1) AS cnt FROM crm_customer c WHERE c.del_flag = '0' AND c.create_time >= DATE_FORMAT(DATE_SUB(NOW(), INTERVAL 5 MONTH), '%Y-%m-01')
${params.dataScope}
GROUP BY month ORDER BY month
